import https from 'https';

/**
 * Test script for Trigger.dev scheduled task
 * 
 * This script triggers the task immediately for testing and prints the Run ID.
 */

const TASK_ID = "scheduled-sync-scheduled_sync__qqxXoTS";
const PROJECT_REF = "proj_qmjtfxoknmfupeecpjod";

// Read the access token from CLI config
function getAccessToken(): string {
  const fs = require('fs');
  const configPath = '/root/.config/trigger/config.json';

  try {
    const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));
    return config.profiles.default.accessToken;
  } catch (error) {
    console.error('Error reading Trigger.dev config:', error);
    throw error;
  }
}

function triggerTask(): Promise<void> {
  return new Promise((resolve, reject) => {
    const accessToken = getAccessToken();
    const data = JSON.stringify({});

    const options = {
      hostname: 'api.trigger.dev',
      port: 443,
      path: `/v3/projects/${PROJECT_REF}/tasks/${TASK_ID}/trigger`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${accessToken}`,
        'Content-Length': data.length
      }
    };

